const input = $json;
const name = input.name || `${input.first_name || ''} ${input.last_name || ''}`.trim() || 'Unknown';
const email = input.email || 'N/A';
const phone = input.phone || 'N/A';
const source = input.source || 'website';
const serviceType = input.service_type || input.service || 'Not specified';
const message = input.message || '';
const leadScore = parseInt(input.lead_score) || 0;
const leadTier = input.lead_tier || 'unscored';

// Determine urgency based on score
let urgency, urgencyEmoji;
if (leadScore >= 80) {
  urgency = 'HOT';
  urgencyEmoji = '\ud83d\udd25\ud83d\udd25\ud83d\udd25';
} else if (leadScore >= 50) {
  urgency = 'WARM';
  urgencyEmoji = '\ud83d\udfe1\ud83d\udfe1';
} else {
  urgency = 'COOL';
  urgencyEmoji = '\ud83d\udd35';
}

// Check for high-value services
const highAovServices = ['hardscaping', 'gutter guard', 'gutter guards', 'patio', 'retaining wall', 'landscape design', 'full renovation'];
const isHighAov = highAovServices.some(s => serviceType.toLowerCase().includes(s));

// Calculate response deadline (5 min from now in CT)
const deadline = new Date(Date.now() + 5 * 60 * 1000);
const deadlineStr = deadline.toLocaleString('en-US', { timeZone: 'America/Chicago', hour: 'numeric', minute: '2-digit', hour12: true });

return [{ json: {
  name,
  email,
  phone,
  source,
  service_type: serviceType,
  message,
  lead_score: leadScore,
  lead_tier: leadTier,
  urgency,
  urgency_emoji: urgencyEmoji,
  is_high_aov: isHighAov,
  response_deadline: deadlineStr
} }];

const d = $json;
const tierEmoji = { 'hot': '\ud83d\udd25', 'warm': '\ud83d\udfe1', 'cold': '\ud83d\udd35' };

let lines = [
  `${d.urgency_emoji} NEW LEAD ALERT`,
  ``,
  `\ud83d\udc64 ${d.name} | ${d.phone}`,
  `\ud83d\udce7 ${d.email}`,
  `\ud83d\udce1 Source: ${d.source}`,
  `\ud83d\udd27 Service: ${d.service_type}`,
  `\ud83c\udfaf Score: ${d.lead_score} (${d.lead_tier}) ${tierEmoji[d.lead_tier] || ''}`
];

if (d.is_high_aov) {
  lines.push(`\ud83d\udcb0 HIGH VALUE SERVICE`);
}

if (d.message) {
  lines.push(``);
  lines.push(`\ud83d\udcac Message: ${d.message}`);
}

lines.push(``);
lines.push(`\u23f0 Response deadline: ${d.response_deadline}`);
lines.push(`\ud83d\udcde Call NOW: tel:${(d.phone || '').replace(/[^+\d]/g, '')}`);

return [{ json: { alert_message: lines.join('\n'), ...d } }];
